CREATE TYPE "MembershipRole" AS ENUM ('OWNER','ADMIN','SALES_AGENT','VIEWER');
CREATE TYPE "MembershipStatus" AS ENUM ('ACTIVE','DISABLED');
CREATE TYPE "BusinessCategory" AS ENUM ('CLOTHING','FURNITURE','BEAUTY','ELECTRONICS','SERVICES','OTHER');
CREATE TYPE "Currency" AS ENUM ('USD','LBP');
CREATE TYPE "CustomerSource" AS ENUM ('WHATSAPP','INSTAGRAM','FACEBOOK','WEBSITE','PHONE','WALK_IN','REFERRAL','OTHER');
CREATE TYPE "LifecycleStage" AS ENUM ('NEW_LEAD','CONTACTED','QUALIFIED','PROPOSAL_SENT','NEGOTIATION','WON','LOST','EXISTING_CUSTOMER');
CREATE TYPE "FollowUpPriority" AS ENUM ('LOW','MEDIUM','HIGH','URGENT');
CREATE TYPE "FollowUpStatus" AS ENUM ('PENDING','IN_PROGRESS','COMPLETED','CANCELLED','OVERDUE');
CREATE TYPE "ActivityType" AS ENUM ('CUSTOMER_CREATED','NOTE_ADDED','TAG_ADDED','TAG_REMOVED','LEAD_STAGE_CHANGED','FOLLOW_UP_CREATED','FOLLOW_UP_COMPLETED');
CREATE TYPE "SubscriptionPlan" AS ENUM ('STARTER','GROWTH','PRO');
CREATE TYPE "SubscriptionStatus" AS ENUM ('TRIALING','ACTIVE','PAST_DUE','CANCELLED','EXPIRED');

CREATE TABLE "User" ("id" UUID PRIMARY KEY, "email" TEXT NOT NULL UNIQUE, "passwordHash" TEXT NOT NULL, "firstName" TEXT NOT NULL, "lastName" TEXT NOT NULL, "emailVerifiedAt" TIMESTAMP(3), "isActive" BOOLEAN NOT NULL DEFAULT true, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, "deletedAt" TIMESTAMP(3));
CREATE TABLE "Business" ("id" UUID PRIMARY KEY, "name" TEXT NOT NULL, "slug" TEXT NOT NULL UNIQUE, "category" "BusinessCategory", "country" TEXT NOT NULL DEFAULT 'LB', "currency" "Currency" NOT NULL DEFAULT 'USD', "timezone" TEXT NOT NULL DEFAULT 'Asia/Beirut', "phone" TEXT, "logoUrl" TEXT, "employeeRange" TEXT, "mainObjective" TEXT, "onboardingComplete" BOOLEAN NOT NULL DEFAULT false, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, "deletedAt" TIMESTAMP(3));
CREATE TABLE "BusinessMember" ("id" UUID PRIMARY KEY, "businessId" UUID NOT NULL REFERENCES "Business"("id") ON DELETE CASCADE, "userId" UUID NOT NULL REFERENCES "User"("id") ON DELETE CASCADE, "role" "MembershipRole" NOT NULL, "status" "MembershipStatus" NOT NULL DEFAULT 'ACTIVE', "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, UNIQUE("businessId","userId"));
CREATE INDEX "BusinessMember_userId_status_idx" ON "BusinessMember"("userId","status"); CREATE INDEX "BusinessMember_businessId_role_idx" ON "BusinessMember"("businessId","role");
CREATE TABLE "RefreshToken" ("id" UUID PRIMARY KEY, "userId" UUID NOT NULL REFERENCES "User"("id") ON DELETE CASCADE, "familyId" UUID NOT NULL, "tokenHash" TEXT NOT NULL UNIQUE, "expiresAt" TIMESTAMP(3) NOT NULL, "revokedAt" TIMESTAMP(3), "replacedBy" UUID, "userAgent" TEXT, "ipAddress" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP); CREATE INDEX "RefreshToken_userId_familyId_idx" ON "RefreshToken"("userId","familyId"); CREATE INDEX "RefreshToken_expiresAt_idx" ON "RefreshToken"("expiresAt");
CREATE TABLE "PasswordResetToken" ("id" UUID PRIMARY KEY, "userId" UUID NOT NULL REFERENCES "User"("id") ON DELETE CASCADE, "tokenHash" TEXT NOT NULL UNIQUE, "expiresAt" TIMESTAMP(3) NOT NULL, "usedAt" TIMESTAMP(3), "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Invitation" ("id" UUID PRIMARY KEY, "businessId" UUID NOT NULL REFERENCES "Business"("id") ON DELETE CASCADE, "email" TEXT NOT NULL, "role" "MembershipRole" NOT NULL, "tokenHash" TEXT NOT NULL UNIQUE, "expiresAt" TIMESTAMP(3) NOT NULL, "acceptedAt" TIMESTAMP(3), "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, UNIQUE("businessId","email")); CREATE INDEX "Invitation_businessId_expiresAt_idx" ON "Invitation"("businessId","expiresAt");
CREATE TABLE "Customer" ("id" UUID PRIMARY KEY, "businessId" UUID NOT NULL REFERENCES "Business"("id") ON DELETE CASCADE, "firstName" TEXT NOT NULL, "lastName" TEXT, "phone" TEXT, "normalizedPhone" TEXT, "email" TEXT, "normalizedEmail" TEXT, "company" TEXT, "address" TEXT, "city" TEXT, "country" TEXT NOT NULL DEFAULT 'LB', "source" "CustomerSource" NOT NULL DEFAULT 'OTHER', "lifecycleStage" "LifecycleStage" NOT NULL DEFAULT 'NEW_LEAD', "assignedUserId" UUID REFERENCES "User"("id") ON DELETE SET NULL, "marketingOptIn" BOOLEAN NOT NULL DEFAULT false, "optedOutAt" TIMESTAMP(3), "totalOrders" INTEGER NOT NULL DEFAULT 0, "totalSpent" DECIMAL(14,2) NOT NULL DEFAULT 0, "lastContactAt" TIMESTAMP(3), "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, "deletedAt" TIMESTAMP(3), UNIQUE("businessId","normalizedPhone"), UNIQUE("businessId","normalizedEmail")); CREATE INDEX "Customer_businessId_lifecycleStage_idx" ON "Customer"("businessId","lifecycleStage"); CREATE INDEX "Customer_businessId_assignedUserId_idx" ON "Customer"("businessId","assignedUserId"); CREATE INDEX "Customer_businessId_createdAt_idx" ON "Customer"("businessId","createdAt");
CREATE TABLE "Tag" ("id" UUID PRIMARY KEY, "businessId" UUID NOT NULL REFERENCES "Business"("id") ON DELETE CASCADE, "name" TEXT NOT NULL, "color" TEXT NOT NULL, "description" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, UNIQUE("businessId","name")); CREATE INDEX "Tag_businessId_idx" ON "Tag"("businessId");
CREATE TABLE "CustomerTag" ("businessId" UUID NOT NULL, "customerId" UUID NOT NULL REFERENCES "Customer"("id") ON DELETE CASCADE, "tagId" UUID NOT NULL REFERENCES "Tag"("id") ON DELETE CASCADE, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY("customerId","tagId")); CREATE INDEX "CustomerTag_businessId_tagId_idx" ON "CustomerTag"("businessId","tagId");
CREATE TABLE "CustomerNote" ("id" UUID PRIMARY KEY, "businessId" UUID NOT NULL REFERENCES "Business"("id") ON DELETE CASCADE, "customerId" UUID NOT NULL REFERENCES "Customer"("id") ON DELETE CASCADE, "authorId" UUID NOT NULL REFERENCES "User"("id"), "content" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, "deletedAt" TIMESTAMP(3)); CREATE INDEX "CustomerNote_businessId_customerId_createdAt_idx" ON "CustomerNote"("businessId","customerId","createdAt");
CREATE TABLE "Activity" ("id" UUID PRIMARY KEY, "businessId" UUID NOT NULL REFERENCES "Business"("id") ON DELETE CASCADE, "customerId" UUID REFERENCES "Customer"("id") ON DELETE CASCADE, "actorId" UUID REFERENCES "User"("id") ON DELETE SET NULL, "type" "ActivityType" NOT NULL, "metadata" JSONB, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP); CREATE INDEX "Activity_businessId_createdAt_idx" ON "Activity"("businessId","createdAt"); CREATE INDEX "Activity_businessId_customerId_createdAt_idx" ON "Activity"("businessId","customerId","createdAt");
CREATE TABLE "FollowUp" ("id" UUID PRIMARY KEY, "businessId" UUID NOT NULL REFERENCES "Business"("id") ON DELETE CASCADE, "customerId" UUID NOT NULL REFERENCES "Customer"("id") ON DELETE CASCADE, "assignedUserId" UUID NOT NULL REFERENCES "User"("id"), "createdById" UUID NOT NULL REFERENCES "User"("id"), "title" TEXT NOT NULL, "description" TEXT, "dueAt" TIMESTAMP(3) NOT NULL, "priority" "FollowUpPriority" NOT NULL DEFAULT 'MEDIUM', "status" "FollowUpStatus" NOT NULL DEFAULT 'PENDING', "reminderAt" TIMESTAMP(3), "completedAt" TIMESTAMP(3), "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, "deletedAt" TIMESTAMP(3)); CREATE INDEX "FollowUp_businessId_dueAt_status_idx" ON "FollowUp"("businessId","dueAt","status"); CREATE INDEX "FollowUp_businessId_assignedUserId_idx" ON "FollowUp"("businessId","assignedUserId");
CREATE TABLE "Pipeline" ("id" UUID PRIMARY KEY, "businessId" UUID NOT NULL REFERENCES "Business"("id") ON DELETE CASCADE, "name" TEXT NOT NULL, "isDefault" BOOLEAN NOT NULL DEFAULT false, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, UNIQUE("businessId","name")); CREATE INDEX "Pipeline_businessId_idx" ON "Pipeline"("businessId");
CREATE TABLE "PipelineStage" ("id" UUID PRIMARY KEY, "businessId" UUID NOT NULL REFERENCES "Business"("id") ON DELETE CASCADE, "pipelineId" UUID NOT NULL REFERENCES "Pipeline"("id") ON DELETE CASCADE, "name" TEXT NOT NULL, "position" INTEGER NOT NULL, "probability" INTEGER NOT NULL DEFAULT 0, "color" TEXT NOT NULL, "isWon" BOOLEAN NOT NULL DEFAULT false, "isLost" BOOLEAN NOT NULL DEFAULT false, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, UNIQUE("pipelineId","position"), UNIQUE("pipelineId","name")); CREATE INDEX "PipelineStage_businessId_idx" ON "PipelineStage"("businessId");
CREATE TABLE "Lead" ("id" UUID PRIMARY KEY, "businessId" UUID NOT NULL REFERENCES "Business"("id") ON DELETE CASCADE, "pipelineId" UUID NOT NULL REFERENCES "Pipeline"("id") ON DELETE CASCADE, "stageId" UUID NOT NULL REFERENCES "PipelineStage"("id"), "customerId" UUID NOT NULL REFERENCES "Customer"("id") ON DELETE CASCADE, "assignedUserId" UUID REFERENCES "User"("id") ON DELETE SET NULL, "title" TEXT NOT NULL, "estimatedValue" DECIMAL(14,2) NOT NULL DEFAULT 0, "currency" "Currency" NOT NULL DEFAULT 'USD', "probability" INTEGER NOT NULL, "expectedCloseDate" TIMESTAMP(3), "source" "CustomerSource" NOT NULL DEFAULT 'OTHER', "notes" TEXT, "lostReason" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, "deletedAt" TIMESTAMP(3)); CREATE INDEX "Lead_businessId_stageId_idx" ON "Lead"("businessId","stageId"); CREATE INDEX "Lead_businessId_assignedUserId_idx" ON "Lead"("businessId","assignedUserId"); CREATE INDEX "Lead_businessId_customerId_idx" ON "Lead"("businessId","customerId");
CREATE TABLE "Subscription" ("id" UUID PRIMARY KEY, "businessId" UUID NOT NULL UNIQUE REFERENCES "Business"("id") ON DELETE CASCADE, "plan" "SubscriptionPlan" NOT NULL DEFAULT 'STARTER', "status" "SubscriptionStatus" NOT NULL DEFAULT 'TRIALING', "trialStart" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "trialEnd" TIMESTAMP(3) NOT NULL, "billingCycle" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "UsageRecord" ("id" UUID PRIMARY KEY, "businessId" UUID NOT NULL REFERENCES "Business"("id") ON DELETE CASCADE, "metric" TEXT NOT NULL, "quantity" INTEGER NOT NULL, "periodStart" TIMESTAMP(3) NOT NULL, "periodEnd" TIMESTAMP(3) NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, UNIQUE("businessId","metric","periodStart")); CREATE INDEX "UsageRecord_businessId_periodEnd_idx" ON "UsageRecord"("businessId","periodEnd");
CREATE TABLE "AuditLog" ("id" UUID PRIMARY KEY, "businessId" UUID NOT NULL REFERENCES "Business"("id") ON DELETE CASCADE, "actorId" UUID REFERENCES "User"("id") ON DELETE SET NULL, "action" TEXT NOT NULL, "entityType" TEXT, "entityId" TEXT, "metadata" JSONB, "ipAddress" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP); CREATE INDEX "AuditLog_businessId_createdAt_idx" ON "AuditLog"("businessId","createdAt"); CREATE INDEX "AuditLog_businessId_entityType_entityId_idx" ON "AuditLog"("businessId","entityType","entityId");
